import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';

function ImageAnalyzer() {
  const [selectedImage, setSelectedImage] = useState(null);
  const [preview, setPreview] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [results, setResults] = useState(null);
  const navigate = useNavigate();

  const handleImageSelect = (e) => {
    const file = e.target.files?.[0];
    if (file) {
      setSelectedImage(file);
      const reader = new FileReader();
      reader.onload = (event) => {
        setPreview(event.target?.result);
      };
      reader.readAsDataURL(file);
      setError('');
      setResults(null);
    }
  };

  const handleAnalyze = async () => {
    if (!selectedImage) {
      setError('Please select an image first');
      return;
    }

    setLoading(true);
    setError('');
    setResults(null);

    try {
      compressImage(selectedImage, async (compressedBase64) => {
        const response = await axios.post('/api/ai/analyze-image', {
          image: compressedBase64,
          imageType: 'image/jpeg'
        });

        const productsResponse = await axios.get('/api/products');
        const allProducts = productsResponse.data;

        const keywords = response.data.keywords || [];
        const matchingProducts = allProducts.filter(product => {
          const productName = product.name.toLowerCase();
          const productCategory = (product.category || '').toLowerCase();

          return keywords.some(keyword => {
            const kw = keyword.toLowerCase();
            return productName.includes(kw) || productCategory.includes(kw);
          });
        });

        setResults({
          analysis: response.data.analysis,
          keywords: keywords,
          fabric: response.data.fabric,
          item: response.data.item,
          products: matchingProducts.slice(0, 9)
        });

        setLoading(false);
      });
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to analyze image');
      console.error('Error:', err);
      setLoading(false);
    }
  };

  const compressImage = (file, callback) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = (event) => {
      const img = new Image();
      img.src = event.target.result;
      img.onload = () => {
        const canvas = document.createElement('canvas');
        let width = img.width;
        let height = img.height;

        const maxDim = 2048;
        if (width > height) {
          if (width > maxDim) {
            height = Math.round((height * maxDim) / width);
            width = maxDim;
          }
        } else {
          if (height > maxDim) {
            width = Math.round((width * maxDim) / height);
            height = maxDim;
          }
        }

        canvas.width = width;
        canvas.height = height;

        const ctx = canvas.getContext('2d');
        ctx.drawImage(img, 0, 0, width, height);

        const compressedBase64 = canvas.toDataURL('image/jpeg', 0.85).split(',')[1];
        callback(compressedBase64);
      };
    };
  };

  const handleClear = () => {
    setSelectedImage(null);
    setPreview(null);
    setResults(null);
    setError('');
  };

  return (
    <div style={{ minHeight: '100vh', backgroundColor: '#fff', fontFamily: 'Helvetica, Arial, sans-serif' }}>
      {/* Header */}
      <div style={{
        padding: '30px 50px 8px 50px',
        borderBottom: '3px solid #000',
        display: 'flex',
        alignItems: 'flex-end',
        gap: '30px'
      }}>
        <img
          src="/CEE.svg"
          alt="CEE Logo"
          style={{
            height: '50px',
            width: 'auto'
          }}
        />
        <h1 style={{
          fontSize: '52px',
          fontWeight: '300',
          letterSpacing: '2px',
          color: '#000',
          margin: '0',
          lineHeight: '1',
          fontFamily: 'Helvetica, Arial, sans-serif'
        }}>
          STYLE DISCOVERY.
        </h1>
      </div>

      {/* Main Content */}
      <div style={{
        display: 'grid',
        gridTemplateColumns: '1fr 1.5fr',
        gap: '0',
        minHeight: 'calc(100vh - 120px)'
      }}>
        {/* Left Side */}
        <div style={{
          backgroundColor: '#fff',
          padding: '60px 50px',
          display: 'flex',
          flexDirection: 'column',
          borderRight: '1px solid #ddd'
        }}>
          {/* Description Text */}
          <div style={{ marginBottom: '60px', flex: 1 }}>
            <p style={{
              fontSize: '16px',
              fontWeight: '400',
              color: '#000',
              lineHeight: '1.8',
              margin: '0'
            }}>
              {results ? (
                <>
                  <strong>AI Analysis:</strong>
                  <br />
                  {results.analysis}
                </>
              ) : (
                'This is where the AI comment created'
              )}
            </p>

            {results && (results.item || results.fabric) && (
              <div style={{ marginTop: '20px', display: 'flex', gap: '10px', flexWrap: 'wrap' }}>
                {results.item && (
                  <span style={{
                    backgroundColor: '#000',
                    color: '#fff',
                    padding: '6px 12px',
                    fontSize: '10px',
                    fontWeight: '600',
                    letterSpacing: '0.5px',
                    textTransform: 'uppercase'
                  }}>
                    {results.item}
                  </span>
                )}
                {results.fabric && (
                  <span style={{
                    backgroundColor: '#333',
                    color: '#fff',
                    padding: '6px 12px',
                    fontSize: '10px',
                    fontWeight: '600',
                    letterSpacing: '0.5px',
                    textTransform: 'uppercase'
                  }}>
                    {results.fabric}
                  </span>
                )}
              </div>
            )}
          </div>

          {/* Buttons */}
          <div style={{ display: 'flex', flexDirection: 'column', gap: '0' }}>
            {selectedImage ? (
              <>
                <button
                  onClick={handleAnalyze}
                  disabled={loading}
                  style={{
                    padding: '18px 30px',
                    backgroundColor: '#000',
                    color: '#fff',
                    border: 'none',
                    fontSize: '14px',
                    fontWeight: '500',
                    letterSpacing: '1px',
                    textTransform: 'uppercase',
                    cursor: loading ? 'not-allowed' : 'pointer',
                    fontFamily: 'Helvetica, Arial, sans-serif'
                  }}
                >
                  {loading ? 'Analyzing...' : 'Confirm'}
                </button>

                <button
                  onClick={handleClear}
                  style={{
                    padding: '18px 30px',
                    backgroundColor: '#fff',
                    color: '#000',
                    border: '1px solid #000',
                    fontSize: '14px',
                    fontWeight: '500',
                    letterSpacing: '1px',
                    textTransform: 'uppercase',
                    cursor: 'pointer',
                    fontFamily: 'Helvetica, Arial, sans-serif'
                  }}
                >
                  Clear
                </button>
              </>
            ) : (
              <label
                htmlFor="image-input"
                style={{
                  padding: '18px 30px',
                  backgroundColor: '#000',
                  color: '#fff',
                  border: 'none',
                  fontSize: '14px',
                  fontWeight: '500',
                  letterSpacing: '1px',
                  textTransform: 'uppercase',
                  cursor: 'pointer',
                  textAlign: 'center',
                  fontFamily: 'Helvetica, Arial, sans-serif',
                  display: 'block'
                }}
              >
                Upload
              </label>
            )}

            <input
              type="file"
              accept="image/*"
              onChange={handleImageSelect}
              style={{ display: 'none' }}
              id="image-input"
            />
          </div>
        </div>

        {/* Right Side - Featured Image */}
        <div style={{
          backgroundColor: '#f5f5f5',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          overflow: 'hidden',
          position: 'relative'
        }}>
          {preview ? (
            <img
              src={preview}
              alt="Preview"
              style={{
                width: '100%',
                height: '100%',
                objectFit: 'cover'
              }}
            />
          ) : (
            <div style={{
              textAlign: 'center',
              color: '#999'
            }}>
              <p style={{ fontSize: '14px', margin: '0' }}>📸</p>
              <p style={{ fontSize: '13px', margin: '10px 0 0' }}>Upload image to preview</p>
            </div>
          )}
        </div>
      </div>

      {/* Products Section */}
      {results && results.products.length > 0 && (
        <div style={{
          borderTop: '1px solid #ddd',
          padding: '60px 50px'
        }}>
          <h2 style={{
            fontSize: '13px',
            fontWeight: '600',
            letterSpacing: '1px',
            color: '#000',
            margin: '0 0 40px 0',
            textTransform: 'uppercase'
          }}>
            Similar Products
          </h2>

          <div style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(3, 1fr)',
            gap: '0'
          }}>
            {results.products.map(product => (
              <div
                key={product._id}
                onClick={() => navigate(`/product/${product._id}`)}
                style={{
                  borderRight: '1px solid #f0f0f0',
                  borderBottom: '1px solid #f0f0f0',
                  cursor: 'pointer'
                }}
              >
                <div style={{
                  aspectRatio: '1',
                  backgroundColor: '#f5f5f5',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  overflow: 'hidden'
                }}>
                  <img
                    src={product.media?.featured || `/products/${product._id}.jpg`}
                    alt={product.name}
                    style={{
                      width: '100%',
                      height: '100%',
                      objectFit: 'cover'
                    }}
                  />
                </div>

                <div style={{ padding: '20px' }}>
                  <h4 style={{
                    fontSize: '11px',
                    fontWeight: '600',
                    letterSpacing: '0.5px',
                    color: '#000',
                    margin: '0 0 8px 0',
                    textTransform: 'uppercase'
                  }}>
                    {product.name}
                  </h4>
                  <p style={{
                    fontSize: '12px',
                    fontWeight: '500',
                    color: '#000',
                    margin: '0'
                  }}>
                    ${product.price}
                  </p>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {error && (
        <div style={{
          padding: '20px 50px',
          backgroundColor: '#ffebee',
          color: '#d32f2f',
          fontSize: '12px',
          borderTop: '1px solid #ddd'
        }}>
          {error}
        </div>
      )}
    </div>
  );
}

export default ImageAnalyzer;
